### `GET /dashboard/analytics`

Query parameters:

- `date_from=YYYY-MM-DD`
- `date_to=YYYY-MM-DD`
- `mode=snapshot|live`

Implemented high-level response shape:

```json
{
  "status": "ready | stale | recomputing | insufficient_data | failed",
  "response_version": "dashboard-analytics-v2",
  "dataset": {
    "date_from": "YYYY-MM-DD",
    "date_to": "YYYY-MM-DD",
    "included_sessions": 0,
    "included_days": 0,
    "native_rows": 0,
    "imported_rows": 0,
    "excluded_rows": 0,
    "generated_at": "datetime"
  },
  "models": [
    {
      "outcome": "digit_span | self_report",
      "formula": "string",
      "grouping_field": "date_bin",
      "converged": true,
      "warnings": [],
      "effects": [
        {
          "term": "temperature_z",
          "is_interaction": false,
          "coefficient": 0.0,
          "standard_error": 0.0,
          "statistic": 0.0,
          "p_value": 0.0,
          "ci_95_low": 0.0,
          "ci_95_high": 0.0,
          "direction": "positive | negative | neutral",
          "significant": true
        }
      ]
    }
  ],
  "temperature_summary": {
    "windows": [
      {
        "window_key": "overall | fall_winter | spring_summer",
        "date_from": "YYYY-MM-DD | null",
        "date_to": "YYYY-MM-DD | null",
        "day_count": 0,
        "participant_count": 0,
        "mean_temperature_c": 0.0,
        "sd_temperature_c": 0.0,
        "frequency_bins": [
          {
            "bin_start_c": 0.0,
            "bin_end_c": 1.0,
            "day_count": 0
          }
        ],
        "cold_group": {
          "day_count": 0,
          "participant_count": 0,
          "participant_ids": [],
          "dates": [],
          "days": []
        },
        "hot_group": {
          "day_count": 0,
          "participant_count": 0,
          "participant_ids": [],
          "dates": [],
          "days": []
        }
      }
    ]
  },
  "visualizations": {
    "default_selected_term": "temperature_z",
    "effect_plots": [
      {
        "outcome": "digit_span | self_report",
        "term": "temperature_z",
        "x_label": "Temperature (z)",
        "y_label": "Adjusted outcome",
        "points": [
          {
            "x": 0.0,
            "y": 0.0,
            "date_local": "YYYY-MM-DD"
          }
        ],
        "fitted_line": [
          {
            "x": 0.0,
            "y": 0.0
          }
        ]
      }
    ],
    "weather_annotations": {
      "selected_term": "temperature_z",
      "date_from": "YYYY-MM-DD",
      "date_to": "YYYY-MM-DD"
    }
  }
}
```
